function toAbortError(reason, message = 'Aborted') {
  if (reason && reason.name === 'AbortError') return reason;
  const err = new Error(reason && reason.message ? reason.message : message);
  err.name = 'AbortError';
  return err;
}

export default function pollUntil(check, options = {}) {
  const { interval = 50, timeout, signal } = options;

  return new Promise((resolve, reject) => {
    let timerId;
    let done = false;
    const start = Date.now();

    const cleanup = () => {
      if (timerId) clearTimeout(timerId);
      if (signal) signal.removeEventListener('abort', onAbort);
    };

    const onAbort = () => {
      if (done) return;
      done = true;
      cleanup();
      reject(toAbortError(signal && signal.reason));
    };

    if (signal) {
      if (signal.aborted) {
        reject(toAbortError(signal.reason));
        return;
      }
      signal.addEventListener('abort', onAbort, { once: true });
    }

    const attempt = async () => {
      try {
        const result = await check();
        if (result) {
          done = true;
          cleanup();
          resolve(result);
          return;
        }
      } catch (err) {
        done = true;
        cleanup();
        reject(err);
        return;
      }

      if (timeout != null && Date.now() - start >= timeout) {
        done = true;
        cleanup();
        reject(new Error('Timeout'));
        return;
      }

      timerId = setTimeout(attempt, interval);
    };

    attempt();
  });
}
